#!/bin/bash

# 索克生活TCM测试准备脚本
# 该脚本用于准备TCM多模态测试环境

set -e

# 颜色定义
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[0;33m'
BLUE='\033[0;34m'
NC='\033[0m' # 无颜色

SAMPLE_DIR="/Users/songxu/Developer/suoke_life/services/rag-service/tests/samples"

echo -e "${BLUE}开始准备TCM测试环境...${NC}"

# 创建必要的目录
mkdir -p "$SAMPLE_DIR"
mkdir -p "/Users/songxu/Developer/suoke_life/services/rag-service/tests/test_results"

# 创建示例图像文件（这里我们只是创建一个空白图像，实际应用中应该使用真实的TCM诊断图像）
echo -e "${YELLOW}创建示例TCM图像样本...${NC}"

# 检查是否安装了ImageMagick
if command -v convert &> /dev/null; then
    # 使用ImageMagick创建示例图像
    echo -e "${GREEN}使用ImageMagick创建示例图像...${NC}"
    
    # 创建舌诊示例图像
    convert -size 640x480 xc:pink -fill red -draw "circle 320,240 320,100" \
    -gravity center -pointsize 30 -annotate 0 "舌诊示例" "$SAMPLE_DIR/tongue.jpg"
    
    # 创建面诊示例图像
    convert -size 640x480 xc:wheat -fill brown -draw "circle 320,240 320,180" \
    -gravity center -pointsize 30 -annotate 0 "面诊示例" "$SAMPLE_DIR/face.jpg"
    
    # 创建脉诊示例图像
    convert -size 640x480 gradient:blue-white \
    -draw "line 100,240 540,240" -draw "line 100,280 540,280" -draw "line 100,200 540,200" \
    -gravity center -pointsize 30 -annotate 0 "脉诊示例" "$SAMPLE_DIR/pulse.jpg"
    
    echo -e "${GREEN}✓ 示例图像创建完成${NC}"
else
    # 如果没有ImageMagick，使用Base64编码的小图像
    echo -e "${YELLOW}⚠ 未检测到ImageMagick，使用基本图像代替...${NC}"
    
    # 简单红色图像的Base64编码
    BASE64_TONGUE=""
    
    # 简单棕色图像的Base64编码
    BASE64_FACE=""
    
    # 简单蓝色图像的Base64编码
    BASE64_PULSE=""
    
    # 将Base64编码转换为图像文件
    echo "$BASE64_TONGUE" | base64 --decode > "$SAMPLE_DIR/tongue.jpg"
    echo "$BASE64_FACE" | base64 --decode > "$SAMPLE_DIR/face.jpg"
    echo "$BASE64_PULSE" | base64 --decode > "$SAMPLE_DIR/pulse.jpg"
    
    echo -e "${GREEN}✓ 基本图像创建完成${NC}"
fi

# 创建示例音频文件（在实际应用中应该使用真实的TCM诊断音频）
echo -e "${YELLOW}创建示例TCM音频样本...${NC}"

# 检查是否安装了Sox
if command -v sox &> /dev/null; then
    # 使用Sox创建示例音频
    echo -e "${GREEN}使用Sox创建示例音频...${NC}"
    
    # 创建咳嗽音频示例
    sox -n -r 44100 -c 2 "$SAMPLE_DIR/cough.wav" synth 2 sin 400 sin 600 fade q 0.1 1.9 0.1
    
    # 创建语音音频示例
    sox -n -r 44100 -c 2 "$SAMPLE_DIR/voice.wav" synth 3 sin 200-500 fade q 0.1 2.9 0.1
    
    echo -e "${GREEN}✓ 示例音频创建完成${NC}"
else
    # 如果没有Sox，创建空音频文件
    echo -e "${YELLOW}⚠ 未检测到Sox，创建空音频文件代替...${NC}"
    
    # 创建空音频文件
    touch "$SAMPLE_DIR/cough.wav"
    touch "$SAMPLE_DIR/voice.wav"
    
    echo -e "${YELLOW}⚠ 已创建空音频文件，实际测试时需要替换为真实音频样本${NC}"
fi

echo -e "${GREEN}TCM测试环境准备完成！${NC}"
echo -e "\n${BLUE}创建的样本文件:${NC}"
ls -la "$SAMPLE_DIR"
echo -e "\n${BLUE}现在可以运行测试:${NC}"
echo -e "${YELLOW}cd /Users/songxu/Developer/suoke_life && ./scripts/test_cicd.sh${NC}"
echo -e "\n${GREEN}完成后，测试结果将保存在:${NC}"
echo -e "${BLUE}/Users/songxu/Developer/suoke_life/services/rag-service/tests/test_results/${NC}" 